module multi_pipe_4bit
#(
    parameter size = 4
)
(
    input clk,
    input rst_n,
    input mul_a,
    input mul_b,
    output reg mul_out
);
parameter size = 4;
reg [size-1:0] mul_a_ext;
reg [size-1:0] mul_b_ext;
reg [size-1:0] partial_product [size-1:0];
reg [size-1:0] sum_reg;
reg [size-1:0] carry_reg;
integer i, j;
// Extend input signals
always @(*) begin
    for (i = 0; i < size; i = i + 1) begin
        if (mul_a[i]) begin
            mul_a_ext[i] = mul_a[i];
        end else begin
            mul_a_ext[i] = 1'b0;
        end
        if (mul_b[i]) begin
            mul_b_ext[i] = mul_b[i];
        end else begin
            mul_b_ext[i] = 1'b0;
        end
    end
end
// Generate partial products
always @(*) begin
    for (i = 0; i < size; i = i + 1) begin
        if (mul_b_ext[i] == 1'b1) begin
            partial_product[i] = mul_a_ext << i;
        end else begin
            partial_product[i] = 'd0;
        end
    end
end
// Add of partial products
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        for (i = 0; i < size; i = i + 1) begin
            sum_reg[i] <= 'd0;
            carry_reg[i] <= 'd0;
        end
    end else begin
        for (i = 0; i < size; i = i + 1) begin
            {carry_reg[i], sum_reg[i]} <= partial_product[i] + sum_reg[i-1];
        end
    end
end
// Final product calculation
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        mul_out <= 'd0;
    end else begin
        for (i = 0; i < size; i = i + 1) begin
            mul_out <= mul_out + sum_reg[i];
        end
    end
end
endmodule
